import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { AdminSetting } from '../../core/models';

interface ServiceGroup {
  service: string;
  title: string;
  blurb: string;
  settings: AdminSetting[];
  configured: boolean;
}

/**
 * Admin settings (manager only). Lists each backing service (PostgreSQL, MinIO,
 * LLM) with a configured/unconfigured badge and a per-service credential form
 * wired to /api/admin/settings. Values arrive masked from the backend.
 */
@Component({
  selector: 'app-settings',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './settings.component.html',
  styleUrl: './settings.component.css',
})
export class SettingsComponent {
  readonly saving = signal(false);
  readonly saved = signal(false);

  readonly settings = signal<AdminSetting[]>([
    { key: 'DATABASE_URL', service: 'postgresql', label: 'Connection URL', value: '••••••••', configured: true },
    { key: 'MINIO_ENDPOINT', service: 'minio', label: 'Endpoint', value: '', configured: false },
    { key: 'MINIO_ACCESS_KEY', service: 'minio', label: 'Access key', value: '', configured: false },
    { key: 'MINIO_SECRET_KEY', service: 'minio', label: 'Secret key', value: '', configured: false },
    { key: 'LLM_API_KEY', service: 'llm', label: 'API key', value: '', configured: false },
  ]);

  private readonly meta: Record<string, { title: string; blurb: string }> = {
    postgresql: { title: 'PostgreSQL', blurb: 'Primary database connection.' },
    minio: { title: 'MinIO', blurb: 'S3-compatible object storage.' },
    llm: { title: 'LLM Provider', blurb: 'Model API used for assistive features.' },
  };

  readonly groups = computed<ServiceGroup[]>(() => {
    const order = ['postgresql', 'minio', 'llm'];
    return order.map((service) => {
      const settings = this.settings().filter((s) => s.service === service);
      return {
        service,
        title: this.meta[service]?.title ?? service,
        blurb: this.meta[service]?.blurb ?? '',
        settings,
        configured: settings.length > 0 && settings.every((s) => s.configured),
      };
    });
  });

  // Editable draft values keyed by setting key.
  draft: Record<string, string> = {};

  save(): void {
    this.saving.set(true);
    this.saved.set(false);
    // Mock persist — mark edited keys configured.
    this.settings.update((list) =>
      list.map((s) =>
        this.draft[s.key]
          ? { ...s, value: '••••••••', configured: true }
          : s,
      ),
    );
    this.draft = {};
    this.saving.set(false);
    this.saved.set(true);
  }
}
